const batch = [
  {"ext":"au-pol-201","date":"2003-11-01","title":"Murray-Darling Basin First Step (500GL Recovery)","category":"resources","impact_score":6,"confidence_score":0.78,"primary_beneficiaries":["Environmental flows","Downstream irrigators","River communities"],"disadvantaged_groups":["Upstream irrigators losing allocations","Cotton growers"],"revenue_impact":"$500M Living Murray Initiative for 500GL environmental water","corporate_advantage":false,"conflict_of_interest_flags":[],"linked_donations":[],"comparison_country":"United States","comparison_approach":"Colorado River Compact with environmental flow requirements","comparison_outcome":"Australia 500GL insufficient (later raised to 2,750GL in 2012); US also struggled with environmental water","analysis_json":{"corruption_signal_strength":"weak","corruption_signal_reasoning":"Environmental recovery program with transparent objectives. Insufficient volume reflected irrigation lobby influence.","confidence_notes":"MDBA records. Living Murray Initiative documents."},"what_changed":"Before this policy, Australia managed the Murray-Darling Basin without explicit environmental flow targets, prioritizing agricultural water extraction. After the 2002 Living Murray Initiative, the government committed to recovering 500 gigalitres of environmental water through COAG coordination. Upstream irrigators immediately lost allocations to meet targets, though the initial 500GL volume proved insufficient and was later raised to 2,750GL in 2012, demonstrating both environmental need and initial policy capture by agricultural interests.","flag_explanations":[{"label":"Irrigation lobby influence on initial volume","detail":"Initial 500GL recovery target was below scientific recommendations for basin health (later revised to 2,750GL in 2012). Does not prove corruption but demonstrates industry lobbying constrained initial policy ambition."}]},
  {"ext":"au-pol-202","date":"2003-07-01","title":"National Mental Health Plan (Third)","category":"healthcare","impact_score":5,"confidence_score":0.72,"primary_beneficiaries":["Mental health service users","Service providers","Pharmaceutical companies"],"disadvantaged_groups":["Rural/remote communities (access gaps)","Indigenous Australians"],"revenue_impact":"$1.5B over 2003-2008 in mental health funding","corporate_advantage":false,"conflict_of_interest_flags":[],"linked_donations":[],"comparison_country":"New Zealand","comparison_approach":"NZ invested 9% of health budget in mental health vs Australia 7.7%","comparison_outcome":"NZ better funded community mental health; Australia hospital-centric","analysis_json":{"corruption_signal_strength":"none","corruption_signal_reasoning":"Legitimate public health framework.","confidence_notes":"Department of Health mental health reports. COAG agreements."},"what_changed":"Before 2003, Australia's mental health system was fragmented across state and territory boundaries with inconsistent funding. The Third National Mental Health Plan (2003-2008) established $1.5 billion in coordinated funding and aimed to shift toward community-based services. After implementation, the system remained hospital-centric and rural/remote communities continued facing significant access gaps, suggesting the national framework lacked enforcement mechanisms to shift established institutional practices."},
  {"ext":"au-pol-203","date":"2003-02-01","title":"PBS in AUSFTA Negotiations","category":"healthcare","impact_score":7,"confidence_score":0.8,"primary_beneficiaries":["US pharmaceutical companies (Pfizer, Merck, J&J)","Patent holders"],"disadvantaged_groups":["Australian taxpayers","PBS system sustainability","Generic medicine access"],"revenue_impact":"Estimated $1B+ over decade in increased PBS costs from IP concessions","corporate_advantage":true,"conflict_of_interest_flags":[],"linked_donations":[],"comparison_country":"New Zealand","comparison_approach":"NZ PHARMAC maintained independence from US trade pressure","comparison_outcome":"NZ preserved lower drug prices; Australia made PBS concessions under AUSFTA pressure","analysis_json":{"corruption_signal_strength":"moderate","corruption_signal_reasoning":"US pharmaceutical industry lobbied heavily for PBS access changes through AUSFTA. IP extension provisions directly benefited US pharma companies at Australian taxpayer expense.","confidence_notes":"DFAT AUSFTA text Chapter 17. Parliamentary Joint Standing Committee review. Productivity Commission pharma report."},"what_changed":"Before AUSFTA negotiations, the Pharmaceutical Benefits Scheme (PBS) controlled drug prices through reference pricing and evidence-based negotiation. During 2002-2004 negotiations, US pharmaceutical companies (Pfizer, Merck, Johnson & Johnson) conducted intensive lobbying campaigns. After AUSFTA Chapter 17 entered force (2005), Australia implemented stronger intellectual property protections and patent extensions that restricted generic medicine competition, estimated to cost Australian taxpayers $1+ billion per decade while benefiting US pharmaceutical corporations.","flag_explanations":[{"label":"US pharmaceutical industry lobbying through AUSFTA","detail":"Pfizer, Merck, and Johnson & Johnson conducted documented lobbying campaigns during 2002-2004 negotiations. Does not prove corruption but shows clear alignment between industry lobbying and Chapter 17 IP provisions."},{"label":"PBS concessions unique to US trade partner","detail":"Australia made IP concessions in AUSFTA not replicated in other free trade agreements. Indicates negotiating leverage of US pharmaceutical industry influenced Australian policy beyond public interest analysis."}]},
  {"ext":"au-pol-204","date":"2003-07-24","title":"Solomon Islands RAMSI Intervention","category":"defence","impact_score":7,"confidence_score":0.88,"primary_beneficiaries":["Solomon Islands stability","ADF capability development","Regional security"],"disadvantaged_groups":["Australian taxpayers ($2.6B cost)"],"revenue_impact":"$2.6B total RAMSI cost 2003-2017","corporate_advantage":false,"conflict_of_interest_flags":[],"linked_donations":[],"comparison_country":"United Kingdom","comparison_approach":"UK Sierra Leone intervention 2000 with similar stabilisation objectives","comparison_outcome":"Both successful; RAMSI 14-year deployment achieved stability; UK shorter engagement","analysis_json":{"corruption_signal_strength":"none","corruption_signal_reasoning":"Legitimate regional security intervention with broad support.","confidence_notes":"DFAT RAMSI evaluation. ADF deployment records. Parliamentary records."},"what_changed":"Before July 2003, Solomon Islands was experiencing state collapse with armed militias controlling regions and government institutions failing to function. Australia launched the Regional Assistance Mission to Solomon Islands (RAMSI), deploying ADF personnel, federal police, and intelligence operatives. After 14 years of continuous deployment (2003-2017), the Solomon Islands achieved measurable political stability and institutional restoration, though at a total Australian cost of $2.6 billion."},
  {"ext":"au-pol-205","date":"2004-06-07","title":"AusLink White Paper - Integrated Land Transport ($11.8B)","category":"infrastructure","impact_score":7,"confidence_score":0.8,"primary_beneficiaries":["Road construction companies","Freight industry","Toll road operators"],"disadvantaged_groups":["Public transport users","Rail freight","Urban communities near highways"],"revenue_impact":"$11.8B over 5 years; 85% roads, 15% rail","corporate_advantage":true,"conflict_of_interest_flags":[],"linked_donations":[],"comparison_country":"Germany","comparison_approach":"Germany invested equally in road and rail infrastructure (Autobahn and Deutsche Bahn)","comparison_outcome":"Germany maintained balanced transport; Australia 85/15 road bias entrenched car dependency","analysis_json":{"corruption_signal_strength":"moderate","corruption_signal_reasoning":"85% road allocation despite rail freight being more efficient. Road construction and trucking industry donations documented. Road lobby (AAA) significant political donor.","confidence_notes":"AusLink White Paper 2004. Infrastructure Australia later criticised road bias."},"what_changed":"Before AusLink (2004), Australian transport funding was fragmented across departments and states. The White Paper allocated $11.8 billion over five years with a decisive 85/15 split: 85% to roads, 15% to rail and other modes. After implementation, this bias entrenched car dependency in Australian metropolitan areas and prioritized trucking industry logistics while rail freight (which is demonstrably more efficient for bulk cargo) remained chronically underfunded.","flag_explanations":[{"label":"85% road vs 15% rail allocation bias","detail":"Rail freight is measurably more efficient for bulk cargo but received one-fifth of road funding. Australian Automobile Association and National Road Transport Association documented political donors during this period."},{"label":"Road construction industry benefits","detail":"Road construction companies direct recipients of 85% of $11.8B allocation. Does not prove corruption but shows clear alignment of industry preferences with policy allocation outcomes."}]},
  {"ext":"au-pol-206","date":"2004-08-03","title":"Australia-US Free Trade Agreement (AUSFTA)","category":"trade","impact_score":8,"confidence_score":0.85,"primary_beneficiaries":["US pharmaceutical companies","US IP holders","Services exporters","Beef/dairy sector"],"disadvantaged_groups":["PBS (higher drug costs)","Sugar industry (excluded)","Cultural industries","Generic medicines"],"revenue_impact":"Trade grew but modest GDP impact (0.02-0.04%); PBS IP costs $1B+","corporate_advantage":true,"conflict_of_interest_flags":[],"linked_donations":[],"comparison_country":"Canada","comparison_approach":"Canada NAFTA negotiated stronger cultural exemptions and dairy protections","comparison_outcome":"Australia made larger PBS/IP concessions; sugar excluded entirely; Canada protected cultural/dairy sectors","analysis_json":{"corruption_signal_strength":"moderate","corruption_signal_reasoning":"US pharmaceutical lobby achieved PBS concessions. Australian sugar excluded despite being top export priority. Trade benefits modest while IP costs significant.","confidence_notes":"DFAT AUSFTA text. CIE economic modelling. Parliamentary review."},"what_changed":"Before AUSFTA, Australia negotiated trade bilaterally with autonomous control over sensitive sectors. The 2004 agreement required 26 chapters covering intellectual property, government procurement, and services. After ratification (January 2005), Australia made unprecedented concessions: PBS faced IP-driven drug cost increases, the sugar industry was entirely excluded despite being a top export priority, and generic competition became restricted. Trade benefits proved modest (0.02-0.04% GDP growth) while costs to PBS were substantial.","flag_explanations":[{"label":"US pharmaceutical lobbying captured PBS concessions","detail":"Documented pharmaceutical industry lobbying during AUSFTA negotiations achieved IP extensions unavailable in other agreements. Does not prove corruption but shows clear industry influence on negotiating outcomes."},{"label":"Sugar industry entirely excluded despite top export priority","detail":"Australia excluded sugar from AUSFTA despite being a top export priority, demonstrating domestic political pressure from other interests. Asymmetric outcomes suggest negotiating power imbalance."},{"label":"Modest trade benefits vs. significant PBS costs","detail":"Trade agreement generated 0.02-0.04% GDP impact but PBS concessions cost $1B+ per decade. Cost-benefit asymmetry raises questions about negotiating priorities and industry influence."}]},
  {"ext":"au-pol-207","date":"2004-01-01","title":"Broadcasting Services Amendment (Media Ownership) Act","category":"media","impact_score":5,"confidence_score":0.72,"primary_beneficiaries":["Media companies","Cross-media ownership aspirants"],"disadvantaged_groups":["Media diversity","Local journalism","Community media"],"revenue_impact":"Paved way for media consolidation; Nine/Fairfax merger 2018","corporate_advantage":true,"conflict_of_interest_flags":[],"linked_donations":[],"comparison_country":"Germany","comparison_approach":"Germany maintained strict cross-media ownership limits through KEK regulator","comparison_outcome":"Germany preserved media diversity; Australia enabled consolidation","analysis_json":{"corruption_signal_strength":"weak","corruption_signal_reasoning":"Media ownership reform aligned with industry desires. Media companies documented political donors.","confidence_notes":"BSA amendments. ACMA media ownership records."},"what_changed":"Before 2004, Australia maintained cross-media ownership rules preventing single entities from owning newspapers, TV, and radio in the same market. The Broadcasting Services Amendment (Media Ownership) Act 2004 progressively relaxed these limits. After deregulation, consolidation accelerated dramatically: Nine merger with Fairfax (2018) created unprecedented concentration of Australian journalism in a single corporate structure, directly reducing the number of independent newsrooms and local journalists."},
  {"ext":"au-pol-208","date":"2004-01-01","title":"Collins Class Submarine Capability Upgrade","category":"defence","impact_score":7,"confidence_score":0.78,"primary_beneficiaries":["ASC (Australian Submarine Corporation)","Raytheon","Defence contractors"],"disadvantaged_groups":["Taxpayers (cost overruns)","Social spending opportunity cost"],"revenue_impact":"$1.4B upgrade program; total Collins program cost ~$6B (originally $3.9B)","corporate_advantage":true,"conflict_of_interest_flags":[],"linked_donations":[],"comparison_country":"Sweden","comparison_approach":"Sweden Gotland-class submarines delivered on time and budget by Kockums","comparison_outcome":"Swedish submarines cost $100M each vs Collins $1B+; Collins plagued by defects and delays","analysis_json":{"corruption_signal_strength":"moderate","corruption_signal_reasoning":"Massive cost overruns from $3.9B to $6B+. Single contractor (ASC) without competitive pressure. Defence procurement concentration documented.","confidence_notes":"ANAO Collins submarine audits. Senate Estimates transcripts. Defence annual reports."},"what_changed":"Before the Collins-class submarine capability upgrade (2004), Australia operated six submarines with chronic problems including poor availability and capability gaps. The $1.4 billion upgrade program aimed to improve combat systems and availability. However, the submarine program had already tripled in cost from original $3.9 billion estimate to $6+ billion—a 54% overrun—making this upgrade one of Australia's costliest defence failures with long-term impacts on budget sustainability.","flag_explanations":[{"label":"Single-contractor procurement without competition","detail":"Australian Submarine Corporation was sole prime contractor without competitive alternatives. Single-source procurement creates cost escalation without competitive discipline."},{"label":"Massive cost overruns (54% above original budget)","detail":"Collins program cost escalated from $3.9B to $6B+, the highest cost overrun of any major Australian defence project. Does not prove corruption but shows risks of sole-source defence procurement."}]},
  {"ext":"au-pol-209","date":"2004-06-15","title":"Energy White Paper - Securing Australias Energy Future","category":"oil_gas","impact_score":7,"confidence_score":0.78,"primary_beneficiaries":["Coal industry","Gas producers","Fossil fuel sector"],"disadvantaged_groups":["Renewable energy sector","Climate policy","Future generations"],"revenue_impact":"Endorsed fossil fuel expansion; $500M Low Emission Technology Fund (primarily CCS)","corporate_advantage":true,"conflict_of_interest_flags":[],"linked_donations":[],"comparison_country":"Germany","comparison_approach":"Germany Energiewende (2000) committed to renewable energy transition","comparison_outcome":"Germany invested in renewables; Australia Energy White Paper 2004 endorsed continued fossil fuel dependence","analysis_json":{"corruption_signal_strength":"moderate","corruption_signal_reasoning":"White Paper endorsed fossil fuel expansion while Germany was transitioning to renewables. Coal and gas industry lobbying documented. $500M LETDF directed primarily to CCS, not renewables.","confidence_notes":"Energy White Paper 2004. Department of Industry archives."},"what_changed":"Before the Energy White Paper (2004), Australia had policy space to invest in renewable energy alternatives. The White Paper explicitly endorsed continued fossil fuel expansion while allocating only $500 million to low-emission technology development, heavily skewed toward carbon capture and storage (CCS) rather than renewable alternatives. After this policy, Australia's renewable energy investment remained marginal while Germany's Energiewende had already committed to a full renewable transition.","flag_explanations":[{"label":"Coal and gas industry lobbying influence","detail":"Energy White Paper 2004 endorsed continued fossil fuel expansion while Germany was transitioning away. Fossil fuel industry lobbying documented but White Paper endorsed industry preferences."},{"label":"$500M LETDF directed primarily to CCS not renewables","detail":"Low Emission Technology Development Fund allocation heavily skewed toward carbon capture and storage (favored by coal industry) rather than renewable energy investment. Does not prove corruption but shows policy structure aligned with industry preferences."}]},
  {"ext":"au-pol-210","date":"2004-11-01","title":"Extended Medicare Safety Net","category":"healthcare","impact_score":6,"confidence_score":0.78,"primary_beneficiaries":["Medical specialists","Higher-income patients","Private practitioners"],"disadvantaged_groups":["Low-income patients (gap fees persisted)","Medicare sustainability"],"revenue_impact":"$1.3B over 4 years; 80% of benefits went to highest-income quintile","corporate_advantage":true,"conflict_of_interest_flags":[],"linked_donations":[],"comparison_country":"New Zealand","comparison_approach":"NZ maintained lower specialist fees through public hospital system","comparison_outcome":"NZ controlled specialist costs; Australia safety net enabled higher specialist fees, with 80% benefits to wealthiest quintile","analysis_json":{"corruption_signal_strength":"moderate","corruption_signal_reasoning":"80% of Extended Medicare Safety Net benefits flowed to highest-income quintile. AMA lobbied for scheme. Specialist fees increased after introduction.","confidence_notes":"Department of Health EMSN evaluation. ABS health expenditure data. Senate inquiry."},"what_changed":"Before Extended Medicare Safety Net (2004), Australian medical specialists charged unlimited gap fees after patients reached annual thresholds. The safety net policy introduced rebates for high-gap patients but was designed to enable specialist fees to rise further. After implementation, data showed 80% of safety net benefits flowed to the highest-income quintile, subsidizing wealthy Australians' access while specialists raised fees, creating a regressive wealth transfer.","flag_explanations":[{"label":"80% of benefits to highest-income quintile","detail":"Extended Medicare Safety Net distribution data showed regressive benefit allocation. Does not prove corruption but demonstrates policy design benefited wealthy patients disproportionately."},{"label":"Specialist lobby influence on scheme design","detail":"Australian Medical Association lobbied for safety net; specialist fees increased after scheme introduction. Does not prove corruption but shows alignment of doctor union lobbying with policy outcomes."}]},
  {"ext":"au-pol-211","date":"2004-08-13","title":"Marriage Amendment Act (Man-Woman Definition)","category":"resources","impact_score":5,"confidence_score":0.85,"primary_beneficiaries":["Social conservatives","Religious organisations"],"disadvantaged_groups":["LGBTQ+ Australians","Same-sex couples","Marriage equality advocates"],"revenue_impact":"No direct financial impact; amended Marriage Act 1961","corporate_advantage":false,"conflict_of_interest_flags":[],"linked_donations":[],"comparison_country":"Canada","comparison_approach":"Canada legalised same-sex marriage in 2005, one year later","comparison_outcome":"Canada moved to equality; Australia entrenched discrimination until 2017 postal survey","analysis_json":{"corruption_signal_strength":"none","corruption_signal_reasoning":"Social policy with bipartisan support at time. Not driven by corporate interests.","confidence_notes":"Marriage Amendment Act 2004. Parliamentary Hansard. Later reversed by Marriage Amendment (Definition and Religious Freedoms) Act 2017."},"what_changed":"Before the Marriage Amendment Act (2004), the Marriage Act 1961 did not explicitly define marriage. Parliament amended the Act to define marriage as the union of a man and a woman, codifying discrimination against same-sex couples. After 2004, Australia maintained this legal bar for 13 years until the Marriage Amendment (Definition and Religious Freedoms) Act 2017 finally removed the restriction following a 2017 postal survey. Canada, by contrast, legalised same-sex marriage in 2005, one year later."},
  {"ext":"au-pol-212","date":"2004-01-01","title":"National Drug Strategy 2004-2009","category":"healthcare","impact_score":5,"confidence_score":0.72,"primary_beneficiaries":["Drug treatment services","Law enforcement","Harm reduction programs"],"disadvantaged_groups":["Drug users (criminalisation continued)","Indigenous communities"],"revenue_impact":"~$1B over 5 years in drug treatment and prevention","corporate_advantage":false,"conflict_of_interest_flags":[],"linked_donations":[],"comparison_country":"Portugal","comparison_approach":"Portugal decriminalised personal drug use in 2001","comparison_outcome":"Portugal achieved better health outcomes through decriminalisation; Australia maintained criminalisation approach","analysis_json":{"corruption_signal_strength":"none","corruption_signal_reasoning":"Public health strategy with legitimate objectives.","confidence_notes":"National Drug Strategy 2004-2009 document. AIHW substance use data."},"what_changed":"Before the National Drug Strategy 2004-2009, Australia relied on criminal enforcement and abstinence-focused approaches to drug policy. The strategy allocated ~$1 billion over five years to drug treatment and prevention but maintained criminalisation of personal drug use. After implementation, Australia continued treating drug use primarily as a criminal justice issue while Portugal (which decriminalised in 2001) achieved superior health outcomes through harm reduction frameworks."},
  {"ext":"au-pol-213","date":"2004-06-25","title":"National Water Initiative (COAG)","category":"resources","impact_score":8,"confidence_score":0.85,"primary_beneficiaries":["Water market participants","Large irrigators","Water traders","Environmental flows"],"disadvantaged_groups":["Small farmers without water entitlements","Indigenous water rights","Rural communities"],"revenue_impact":"$10B+ National Water Initiative; established water trading worth $3B+ annually","corporate_advantage":true,"conflict_of_interest_flags":[],"linked_donations":[],"comparison_country":"Chile","comparison_approach":"Chile pioneered water markets through 1981 Water Code","comparison_outcome":"Both created water markets; Chile faced environmental degradation from over-extraction; Australia added environmental protections","analysis_json":{"corruption_signal_strength":"moderate","corruption_signal_reasoning":"Water trading created by NWI worth $3B+ annually. Large irrigators captured majority of entitlements. Corporate water holders (Cubbie Station etc.) documented political influence.","confidence_notes":"NWI Intergovernmental Agreement 2004. NWC reports. BOM water account data."},"what_changed":"Before the National Water Initiative (2004), water entitlements were primarily held by governments and allocated to irrigators through administrative processes. COAG agreed to establish water markets worth $3+ billion annually, enabling trading of entitlements. After NWI implementation, water entitlements concentrated in large corporate hands (Cubbie Station and similar operations), creating a $3B+ annual market dominated by agricultural corporations while small farmers and Indigenous communities lacked access to entitlements.","flag_explanations":[{"label":"Water entitlements concentrated in large corporate hands","detail":"Water trading system created $3B+ annual market dominated by large irrigators (Cubbie Station, etc.). Small farmers and Indigenous communities excluded from substantial entitlements. Does not prove corruption but shows market design benefited large initial entitlement holders."}]},
  {"ext":"au-pol-214","date":"2004-07-01","title":"Thailand-Australia FTA","category":"trade","impact_score":6,"confidence_score":0.78,"primary_beneficiaries":["Services exporters","Education sector","Automotive sector (Thai imports)","Thai rice/tuna exporters"],"disadvantaged_groups":["Australian food manufacturers","Canned food industry","Local manufacturers"],"revenue_impact":"Bilateral trade grew from $10B to $20B+ over decade","corporate_advantage":true,"conflict_of_interest_flags":[],"linked_donations":[],"comparison_country":"European Union","comparison_approach":"EU-ASEAN negotiations included labour and environmental standards","comparison_outcome":"Australia TAFTA excluded labour/environmental chapters; EU insisted on these provisions","analysis_json":{"corruption_signal_strength":"weak","corruption_signal_reasoning":"Standard trade agreement with transparent negotiation.","confidence_notes":"DFAT TAFTA text. Trade statistics from ABS."},"what_changed":"Before the Thailand-Australia Free Trade Agreement (2004), bilateral trade was regulated bilaterally. After TAFTA took effect (2005), tariffs on Thai goods decreased while Thai agricultural exports (rice, tuna) gained market access. Australia gained services export opportunities particularly in education and professional services. However, TAFTA excluded labour and environmental standard chapters, unlike comparable EU-ASEAN negotiations which included such provisions."},
  {"ext":"au-pol-215","date":"2004-10-01","title":"Wine Equalisation Tax (WET) Rebate Introduction","category":"subsidy","impact_score":5,"confidence_score":0.75,"primary_beneficiaries":["Small winemakers","Wine industry","Wine tourism"],"disadvantaged_groups":["Government revenue","Public health (alcohol consumption)"],"revenue_impact":"WET rebate cost $300M+ annually; exploited by bulk wine producers","corporate_advantage":true,"conflict_of_interest_flags":[],"linked_donations":[],"comparison_country":"France","comparison_approach":"France supports wine industry through appellation system and export assistance","comparison_outcome":"Australia WET rebate created oversupply; France maintained quality-based support","analysis_json":{"corruption_signal_strength":"weak","corruption_signal_reasoning":"Wine industry lobbying documented. Rebate exploited by bulk producers beyond original small winery intent.","confidence_notes":"Treasury WET rebate data. Winemakers Federation lobbying records."},"what_changed":"Before the Wine Equalisation Tax (WET) Rebate (2004), all wine producers—small and large—paid equivalent tax treatment. The rebate program was designed to support small winemakers but the system was quickly exploited by bulk wine producers who scaled wine production dramatically to capture rebate benefits. After introduction, the WET rebate cost over $300 million annually, benefiting large bulk producers more than the intended small winery sector and distorting wine market incentives."},
  {"ext":"au-pol-216","date":"2005-11-03","title":"Anti-Terrorism Act (No 2) 2005","category":"defence","impact_score":6,"confidence_score":0.8,"primary_beneficiaries":["Security agencies (ASIO, AFP)","Defence contractors","Security industry"],"disadvantaged_groups":["Civil liberties","Muslim communities","Privacy advocates","Media (sedition provisions)"],"revenue_impact":"$200M+ annually in expanded security operations","corporate_advantage":true,"conflict_of_interest_flags":[],"linked_donations":[],"comparison_country":"United Kingdom","comparison_approach":"UK Terrorism Act 2006 with stronger judicial oversight","comparison_outcome":"UK maintained stronger safeguards; Australia control orders and preventative detention with weaker oversight","analysis_json":{"corruption_signal_strength":"weak","corruption_signal_reasoning":"Post-London bombings security legislation. Bipartisan support. Security industry benefited.","confidence_notes":"Anti-Terrorism Act (No 2) 2005. PJCIS reviews."},"what_changed":"Before the Anti-Terrorism Act (No 2) 2005, Australia had targeted counter-terrorism powers. Following the July 2005 London bombings, Parliament passed legislation expanding government surveillance powers, introducing control orders enabling detention without trial, and establishing expanded sedition provisions. After implementation, government security spending increased $200M+ annually, with benefits flowing to ASIO, AFP, and defence contractors. The legislation had bipartisan support limiting corruption signals but clearly benefited security industry interests.","flag_explanations":[{"label":"Security industry benefited from expanded spending","detail":"Anti-terrorism legislation expanded government security spending $200M+ annually. ASIO, AFP, and defence contractors received expanded budgets. Bipartisan support limits corruption signal but shows industry benefited from crisis-driven expansion."}]},
  {"ext":"au-pol-217","date":"2005-06-07","title":"AusLink National Land Transport Plan ($11.8B)","category":"infrastructure","impact_score":7,"confidence_score":0.8,"primary_beneficiaries":["Road construction firms","Freight industry","Toll road operators","Transurban"],"disadvantaged_groups":["Public transport","Rail freight","Urban communities","Climate objectives"],"revenue_impact":"$11.8B; 85% roads, 15% rail","corporate_advantage":true,"conflict_of_interest_flags":[],"linked_donations":[],"comparison_country":"Japan","comparison_approach":"Japan invested heavily in Shinkansen high-speed rail alongside road network","comparison_outcome":"Japan achieved balanced transport; Australia road bias continued","analysis_json":{"corruption_signal_strength":"moderate","corruption_signal_reasoning":"85% road allocation. Road lobby (AAA, NatRoad) documented political donors. Rail freight more efficient but received 15%.","confidence_notes":"AusLink plan. Infrastructure Australia reports."},"what_changed":"Before AusLink (2005 refresh), transport infrastructure remained 85% road-focused. The 2005 National Land Transport Plan reaffirmed this allocation despite mounting evidence that rail is more efficient for bulk freight. After this reaffirmation, the road lobby (Australian Automobile Association, National Road Transport Association) remained influential political donors, while rail freight continued declining as a percentage of total freight moved. Urban communities near highways bore noise and pollution costs while rail remained chronically underfunded.","flag_explanations":[{"label":"Road lobby political donations aligned with allocation outcomes","detail":"Australian Automobile Association and National Road Transport Association documented as political donors. 85% road / 15% rail allocation directly aligned with donor sector preferences. Does not prove corruption but shows alignment of donations and policy benefits."}]},
  {"ext":"au-pol-218","date":"2005-01-01","title":"HECS Fee Deregulation (Higher Education)","category":"education","impact_score":6,"confidence_score":0.78,"primary_beneficiaries":["Universities","Vice-Chancellors","Higher education administrators"],"disadvantaged_groups":["Students","Low-income families","First-in-family students","Regional students"],"revenue_impact":"Fees increased 25-30% in first year; student debt grew to $45B+ outstanding","corporate_advantage":false,"conflict_of_interest_flags":[],"linked_donations":[],"comparison_country":"Germany","comparison_approach":"Germany abolished tuition fees across all states by 2014","comparison_outcome":"Germany free university; Australia moving toward higher debt and fees","analysis_json":{"corruption_signal_strength":"weak","corruption_signal_reasoning":"Fee deregulation benefited university revenue. Universities Australia lobbied for flexibility. Students bore increased cost.","confidence_notes":"HESA 2003 amendments. Department of Education data. ATO HECS-HELP statistics."},"what_changed":"Before HECS Fee Deregulation (2005), Australian universities charged government-set student contribution bands. The Tertiary Education Quality and Standards Framework allowed universities to set fees flexibly above baseline. After deregulation, fees increased 25-30% in the first year, student debt grew to $45B+ outstanding, and first-in-family and low-income student participation declined. Universities increased administrative spending while per-student teaching quality declined, suggesting fee revenue was captured by administrative overhead."},
  {"ext":"au-pol-219","date":"2005-06-01","title":"JSF F-35 Joint Strike Fighter Agreement","category":"defence","impact_score":8,"confidence_score":0.82,"primary_beneficiaries":["Lockheed Martin","BAE Systems Australia","Defence contractors","US alliance"],"disadvantaged_groups":["Taxpayers ($17.2B and rising)","Social spending opportunity cost"],"revenue_impact":"$17.2B for 72 aircraft (originally estimated $12B); ongoing sustainment costs $2B+/yr","corporate_advantage":true,"conflict_of_interest_flags":[],"linked_donations":[],"comparison_country":"France","comparison_approach":"France developed independent Rafale fighter; maintained sovereign capability","comparison_outcome":"France achieved defence sovereignty; Australia dependent on US supply chain with significant cost overruns","analysis_json":{"corruption_signal_strength":"moderate","corruption_signal_reasoning":"Single-source US procurement without competitive tender. $5B+ cost escalation. Lockheed Martin and defence contractors documented political donors. Australian industry participation below promised levels.","confidence_notes":"ANAO JSF audits. Defence budget papers. Senate Estimates transcripts."},"what_changed":"Before the JSF F-35 agreement (2005), Australia had explored multiple fighter aircraft options including the Gripen and Rafale. Australia committed to purchasing 72 JSF F-35 aircraft from Lockheed Martin with original estimate of $12 billion. After this decision, costs escalated to $17.2B ($1.2B per aircraft), making it one of the costliest defence acquisitions per unit. Australian industry participation fell below promised levels despite being a selection criterion, demonstrating post-commitment cost growth in sole-source procurement.","flag_explanations":[{"label":"Single-source Lockheed Martin procurement","detail":"JSF F-35 sole-source contract without competitive alternatives among fighter aircraft options. US defence contractor lobbying documented during selection period. Does not prove corruption but shows single-source risks."},{"label":"Massive cost escalation ($5.2B above estimate)","detail":"JSF cost grew from $12B to $17.2B (43% increase) post-commitment. Single-source procurement enabled cost escalation without competitive alternatives or exit options."},{"label":"Australian industry participation below promised levels","detail":"Defence contractors promised Australian industry participation as selection criterion. After acquisition, actual participation fell below commitments. Does not prove corruption but shows post-commitment industry leverage."}]},
  {"ext":"au-pol-220","date":"2005-01-01","title":"PBS Co-Payment Increase","category":"healthcare","impact_score":5,"confidence_score":0.75,"primary_beneficiaries":["Government budget","Pharmaceutical companies (maintained PBS listing revenue)"],"disadvantaged_groups":["Low-income patients","Chronic disease patients","Elderly Australians"],"revenue_impact":"Co-payment increases shifted ~$150M annually from government to patients","corporate_advantage":true,"conflict_of_interest_flags":[],"linked_donations":[],"comparison_country":"United Kingdom","comparison_approach":"UK NHS prescriptions free in Scotland, Wales, NI; England £9.90 flat","comparison_outcome":"Multiple UK nations abolished prescription charges; Australia increased them","analysis_json":{"corruption_signal_strength":"weak","corruption_signal_reasoning":"Cost-shifting from government to patients.","confidence_notes":"PBS expenditure data. Department of Health reports."},"what_changed":"Before PBS Co-Payment Increase (2005), Australian patients paid flat co-payments ($15-20) regardless of drug cost. The government increased co-payments, shifting approximately $150 million annually from the public budget to patient out-of-pocket costs. After the increase, low-income and chronic disease patients faced higher medication access barriers while pharmaceutical companies maintained PBS listing revenues. The policy regressed cost-sharing toward patients with least ability to pay.","flag_explanations":[{"label":"Cost-shifting from government to patients","detail":"PBS co-payment increases shifted $150M annually from government budget to patient out-of-pocket. Regressive impact on low-income and chronic disease patients."}]},
  {"ext":"au-pol-221","date":"2005-06-01","title":"Pacific Highway Upgrade ($2.2B Federal)","category":"infrastructure","impact_score":6,"confidence_score":0.78,"primary_beneficiaries":["Road construction companies","Freight operators","Regional communities"],"disadvantaged_groups":["Rail alternatives","Environmental corridors","Taxpayers"],"revenue_impact":"$2.2B federal; total program $15B+","corporate_advantage":true,"conflict_of_interest_flags":[],"linked_donations":[],"comparison_country":"Germany","comparison_approach":"Germany balanced Autobahn with rail investment","comparison_outcome":"Australia prioritised road; Germany maintained multimodal transport","analysis_json":{"corruption_signal_strength":"weak","corruption_signal_reasoning":"Major road project with legitimate safety justification. Road construction industry benefited.","confidence_notes":"Federal and NSW government Pacific Highway plans."},"what_changed":"Before Pacific Highway Upgrade ($2.2B federal component, 2005), the Pacific Highway had significant safety risks and congestion. The federal and NSW governments committed $15B+ total for progressive upgrading. After the program began, Australian transport policy remained road-centric: $15B+ in road investment while rail alternatives received minimal funding. Germany balanced Autobahn investment with equivalent rail investment during the same period, maintaining multimodal transport options."},
  {"ext":"au-pol-222","date":"2005-01-01","title":"Private Health Insurance Rebate Increases (65+)","category":"healthcare","impact_score":5,"confidence_score":0.75,"primary_beneficiaries":["Private health insurers","Private hospital operators","Elderly with PHI"],"disadvantaged_groups":["Public hospital system","Taxpayers","Low-income elderly without PHI"],"revenue_impact":"Increased rebate to 35-40% for over-65s; additional $400M+ annually","corporate_advantage":true,"conflict_of_interest_flags":[],"linked_donations":[],"comparison_country":"Canada","comparison_approach":"Canada universal public healthcare for elderly without private insurance subsidies","comparison_outcome":"Canada universal coverage; Australia additional subsidy to private system","analysis_json":{"corruption_signal_strength":"moderate","corruption_signal_reasoning":"Age-based rebate increase further subsidised private insurance industry. Industry directly benefited from government-manufactured demand.","confidence_notes":"PHIAC annual reports. Treasury estimates."},"what_changed":"Before Private Health Insurance Rebate Increases for over-65s (2005), the rebate system treated all age groups similarly. The government increased rebates to 35-40% specifically for those over 65. After implementation, the policy provided additional $400M+ annually in subsidies to private health insurance companies while the public hospital system faced relative budget constraints. The policy directly subsidized private insurance industry revenue extraction from both premiums and government rebates.","flag_explanations":[{"label":"Age-based rebate increase directly benefited private insurers","detail":"Rebate increase to 35-40% for over-65s directly subsidized private health insurance companies. Government effectively transferred $400M+ annually in taxpayer revenue to insurance industry."}]},
  {"ext":"au-pol-223","date":"2005-01-01","title":"Skilling Australia Workforce Fund","category":"education","impact_score":5,"confidence_score":0.7,"primary_beneficiaries":["VET providers","Apprentices","Industry training boards"],"disadvantaged_groups":["University sector (relative funding)"],"revenue_impact":"$1.2B over 4 years in VET funding","corporate_advantage":false,"conflict_of_interest_flags":[],"linked_donations":[],"comparison_country":"Germany","comparison_approach":"Germany dual apprenticeship system with employer co-investment","comparison_outcome":"Germany achieved stronger employer engagement; Australia VET quality variable","analysis_json":{"corruption_signal_strength":"none","corruption_signal_reasoning":"Legitimate workforce development program.","confidence_notes":"DEST program data. NCVER reports."},"what_changed":"Before Skilling Australia Workforce Fund (2005), vocational education training (VET) was underfunded relative to university education. The government allocated $1.2 billion over four years to VET expansion, aiming to strengthen employer engagement. After implementation, VET quality remained variable across states, and universities continued receiving preferred policy treatment. Germany's dual apprenticeship system with mandatory employer co-investment achieved stronger outcomes during the same period."},
  {"ext":"au-pol-224","date":"2005-07-01","title":"Super Fund Choice Introduced (Portability)","category":"superannuation","impact_score":7,"confidence_score":0.82,"primary_beneficiaries":["Retail super funds","Financial advisors","Fund managers"],"disadvantaged_groups":["Industry super funds (increased competition)","Low-balance members (lost insurance)"],"revenue_impact":"Fund portability enabled $50B+ in fund flows; retail fund fees $15B+ annually","corporate_advantage":true,"conflict_of_interest_flags":[],"linked_donations":[],"comparison_country":"United Kingdom","comparison_approach":"UK auto-enrolment with NEST default fund since 2012","comparison_outcome":"UK NEST low-cost default; Australia choice led to proliferation of high-fee retail products","analysis_json":{"corruption_signal_strength":"moderate","corruption_signal_reasoning":"Choice of fund primarily benefited financial advisors and retail fund managers. Retail funds charged higher fees than industry funds. Financial planning industry documented political donors.","confidence_notes":"APRA statistics. Productivity Commission super inquiry 2018."},"what_changed":"Before Super Fund Choice (2005), employees were typically locked into industry super funds chosen by employers or unions. The government introduced portability rules enabling employees to switch to any superannuation fund, particularly retail super funds offered by financial advisors. After portability, $50B+ flowed to retail funds, which charged substantially higher annual fees ($15B+ industry-wide annually) while delivering lower net returns than industry funds. Financial advisors captured significant revenue from switching commissions.","flag_explanations":[{"label":"Retail fund fees substantially exceeded industry fund performance","detail":"Fund choice policy enabled retail funds to charge $15B+ annually in fees while delivering lower net returns than industry funds. Does not prove corruption but shows policy design benefited fee-charging intermediaries."},{"label":"Financial advisor industry benefited from portability commissions","detail":"Fund portability enabled financial advisors to capture switching commissions. Financial planning industry documented as political donors. Does not prove corruption but shows alignment of policy design with industry preferences."}]},
  {"ext":"au-pol-225","date":"2005-05-10","title":"Superannuation Simpler Super Reforms Announced","category":"superannuation","impact_score":8,"confidence_score":0.85,"primary_beneficiaries":["High-wealth super holders","Financial advisors","Self-managed super funds"],"disadvantaged_groups":["Low-income workers","Government revenue","Future retirement system sustainability"],"revenue_impact":"Tax-free super for over-60s cost $8B+ annually in foregone revenue","corporate_advantage":true,"conflict_of_interest_flags":[],"linked_donations":[],"comparison_country":"United Kingdom","comparison_approach":"UK taxes pension withdrawals as income; 25% tax-free lump sum maximum","comparison_outcome":"Australia tax-free withdrawals unique globally; UK captures retirement income tax; Australia foregoes $8B+ annually","analysis_json":{"corruption_signal_strength":"moderate","corruption_signal_reasoning":"Tax-free super for over-60s disproportionately benefits wealthy. Top 10% of super balances receive majority of tax concessions. Financial services industry lobbied for reforms.","confidence_notes":"Treasury Tax Expenditures Statement. Henry Tax Review. Grattan Institute super analysis."},"what_changed":"Before Superannuation Simpler Super Reforms (2005 announcement), retirees over 60 could access super tax-free but with complex withdrawal rules. The reforms (2006-2007 implementation) made superannuation completely tax-free for withdrawals after age 60, a unique global provision unavailable in comparable OECD nations. After implementation, the policy cost the government $8B+ annually in foregone tax revenue, with benefits concentrated in the top wealth decile who held majority of balances. The UK by contrast taxes pension withdrawals as income, capturing retirement-stage taxation.","flag_explanations":[{"label":"Tax-free super for over-60s unique globally and highly regressive","detail":"Australia alone allows complete tax exemption on superannuation withdrawals after 60. Global comparison shows no other OECD nation offers equivalent concession. Top 10% of super balances receive majority of $8B+ annual cost. Does not prove corruption but shows policy design concentrated benefits to wealthy."},{"label":"Financial services industry lobbying for super tax concessions","detail":"Financial services sector lobbied heavily for super tax concessions, directly benefiting from managing large unencumbered super accounts. Does not prove corruption but shows alignment of industry preferences and policy outcomes."}]},
  {"ext":"au-pol-226","date":"2005-07-01","title":"Welfare to Work Reforms - DSP Eligibility Tightened","category":"healthcare","impact_score":6,"confidence_score":0.78,"primary_beneficiaries":["Government budget","Employment services providers"],"disadvantaged_groups":["Disability Support Pension recipients","People with partial work capacity","Mental health sufferers"],"revenue_impact":"$2.1B savings over 4 years; 50,000+ moved from DSP to Newstart","corporate_advantage":true,"conflict_of_interest_flags":[],"linked_donations":[],"comparison_country":"New Zealand","comparison_approach":"NZ maintained more accessible disability support with supported employment","comparison_outcome":"NZ better integration of disability support; Australia pushed vulnerable people to lower Newstart payment","analysis_json":{"corruption_signal_strength":"weak","corruption_signal_reasoning":"Welfare conditionality with cost-saving motive. Employment services providers benefited from increased client base. Vulnerable people pushed to lower payment.","confidence_notes":"FaCS evaluation. Senate Community Affairs inquiry."},"what_changed":"Before the 2006 Australian Summer (reference point), climate change impacts in agriculture were becoming measurable. Between 2006-2007, Australia experienced the worst drought in 1,000 years, devastating agricultural production and water supply. The Millennium Drought (2001-2009 peak) demonstrated climate vulnerability but Australian policy response remained incremental. After the drought's peak impact (2006-2007), the government initiated limited emissions reductions policies while maintaining coal industry support."},
  {"ext":"au-pol-227","date":"2005-12-07","title":"WorkChoices Industrial Relations Reform","category":"industrial_relations","impact_score":9,"confidence_score":0.92,"primary_beneficiaries":["Employers","Business Council of Australia","Retail and hospitality operators","Mining companies"],"disadvantaged_groups":["Low-wage workers","Union members","Casual workers","Women workers"],"revenue_impact":"$1.6B in reduced penalty rates and conditions; real wages stagnated","corporate_advantage":true,"conflict_of_interest_flags":[{"member":"Peter Costello (Treasurer)","interest":"Business sector tax revenue growth","relevance":"WorkChoices designed to reduce labour costs boosting corporate profits"},{"member":"Kevin Andrews (Minister)","interest":"Workplace Relations Minister implemented reforms","relevance":"Direct responsibility for legislation that removed unfair dismissal protections for small business employees"}],"linked_donations":[],"comparison_country":"New Zealand","comparison_approach":"NZ Employment Relations Act 2000 restored collective bargaining after similar 1991 reforms","comparison_outcome":"NZ reversed similar reforms after seeing negative worker outcomes; Australia WorkChoices contributed to 2007 election loss","analysis_json":{"corruption_signal_strength":"strong","corruption_signal_reasoning":"BCA and employer groups actively lobbied for WorkChoices. $55M ACTU Your Rights at Work campaign documented employer-government alignment. AWAs removed penalty rates and conditions for 500,000+ workers. Direct correlation between employer donations and policy outcomes.","confidence_notes":"Parliamentary Hansard. BCA lobbying records. ABS wages data. 2007 election analysis documenting WorkChoices as key factor."},"what_changed":"Before FTZs Expansion (2006), Australia had limited free trade zone infrastructure. The government expanded FTZs to enable manufacturing-for-export without tariff barriers and with streamlined import procedures. After expansion, corporations could import raw materials, manufacture, and re-export with minimal government revenue capture but significant employment concentration in specific regional zones. The policy benefited manufacturing export industries but created geographic inequality in economic activity."},
  {"ext":"au-pol-228","date":"2006-01-01","title":"AWB Oil-for-Food Scandal ($221M Kickbacks)","category":"trade","impact_score":8,"confidence_score":0.9,"primary_beneficiaries":["AWB management","Iraqi regime (Saddam Hussein)","Wheat export monopoly"],"disadvantaged_groups":["Australian taxpayers","International reputation","Iraqi people","Competing wheat exporters"],"revenue_impact":"$221M in kickbacks to Saddam regime via Alia trucking company","corporate_advantage":true,"conflict_of_interest_flags":[{"member":"Howard Government","interest":"AWB maintained wheat export monopoly","relevance":"Cole Inquiry found government knew about concerns but failed to act; Alexander Downer and Mark Vaile received briefings"}],"linked_donations":[],"comparison_country":"Canada","comparison_approach":"Canada Canadian Wheat Board maintained oversight preventing similar corruption","comparison_outcome":"Canada maintained clean wheat exports; Australia AWB paid $221M in kickbacks","analysis_json":{"corruption_signal_strength":"strong","corruption_signal_reasoning":"$221M in kickbacks to Saddam Hussein regime. Cole Inquiry found government officials received briefings about concerns but failed to intervene. AWB privatisation removed government oversight enabling corruption.","confidence_notes":"Cole Inquiry Report 2006. Federal Court AWB proceedings. Parliamentary Hansard."},"what_changed":"Before the Private Hospital Rebate Enhancement (2006), the private health insurance system faced declining affordability. The government increased rebates to encourage PHI take-up, intending to reduce pressure on public hospitals. After enhancement, the policy cost government $500M+ annually in additional subsidies while PHI coverage plateaued below target levels. The policy demonstrated that PHI demand is price-inelastic: further subsidies did not substantially shift public hospital demand downward."},
  {"ext":"au-pol-229","date":"2006-01-01","title":"Childcare Quality Reforms (Staff Ratios)","category":"education","impact_score":5,"confidence_score":0.72,"primary_beneficiaries":["Children","Childcare workers","Quality improvement"],"disadvantaged_groups":["Childcare operators (compliance costs)","Parents (fee increases)"],"revenue_impact":"Compliance costs passed to parents; fees increased 5-10%","corporate_advantage":false,"conflict_of_interest_flags":[],"linked_donations":[],"comparison_country":"Denmark","comparison_approach":"Denmark high staff ratios and publicly funded childcare","comparison_outcome":"Denmark better quality through public funding; Australia quality reforms without adequate funding","analysis_json":{"corruption_signal_strength":"none","corruption_signal_reasoning":"Legitimate quality improvement initiative.","confidence_notes":"ACECQA quality reports. NQF documentation."},"what_changed":"Before Paid Parental Leave Expansion (2006), Australia provided minimal paid parental leave compared to OECD peers. The government expanded paid leave to 4 weeks (subsequently 18 weeks in 2010), enabling more parents to take time after childbirth. After this policy, Australia moved incrementally toward OECD norms, though still below Nordic countries offering 12+ months. The policy benefited working parents and reduced childcare pressure but remained modest by comparative standards."},
  {"ext":"au-pol-230","date":"2006-10-18","title":"Foreign Ownership Media Limits Removed","category":"media","impact_score":7,"confidence_score":0.82,"primary_beneficiaries":["Rupert Murdoch/News Corp","Kerry Stokes/Seven","Media consolidation aspirants"],"disadvantaged_groups":["Media diversity","Local journalism","Community media","Regional news"],"revenue_impact":"Enabled media consolidation; Nine-Fairfax merger 2018 worth $4B","corporate_advantage":true,"conflict_of_interest_flags":[{"member":"Howard Government Communications Minister","interest":"Media industry policy alignment","relevance":"Removal of foreign ownership limits directly benefited News Corp and major media proprietors who were government supporters"}],"linked_donations":[],"comparison_country":"Germany","comparison_approach":"Germany KEK media concentration regulator maintained cross-media limits","comparison_outcome":"Germany preserved media plurality; Australia enabled consolidation reducing diversity","analysis_json":{"corruption_signal_strength":"strong","corruption_signal_reasoning":"Media ownership deregulation directly benefited media proprietors who were documented government supporters. News Corp, Seven, Nine all benefited. Media companies documented political donors.","confidence_notes":"Broadcasting Services Amendment Act 2006. ACMA media ownership reports."},"what_changed":"Before the Horticulture Code of Conduct (2006), large retailers exercised monopsony power against produce suppliers, imposing arbitrary price changes and terms. The voluntary code aimed to improve negotiating balance between retailers and growers. After implementation, the code had limited enforceability and major retailers (Coles, Woolworths) continued unilateral pricing practices. Grower complaints persisted, demonstrating that voluntary codes lack teeth against concentrated buyer power."},
  {"ext":"au-pol-231","date":"2006-10-18","title":"Media Ownership Rules Relaxed (Cross-Media & Foreign)","category":"media","impact_score":7,"confidence_score":0.82,"primary_beneficiaries":["News Corp","Seven West Media","Nine Entertainment","Cross-media aspirants"],"disadvantaged_groups":["Media diversity","Local journalism","Independent media"],"revenue_impact":"Enabled cross-media mergers; media market valued $40B+","corporate_advantage":true,"conflict_of_interest_flags":[],"linked_donations":[],"comparison_country":"Canada","comparison_approach":"Canada CRTC maintained cross-media ownership restrictions","comparison_outcome":"Canada preserved more diverse media landscape; Australia consolidation accelerated","analysis_json":{"corruption_signal_strength":"strong","corruption_signal_reasoning":"Cross-media deregulation benefited major media proprietors. Packer, Murdoch, Stokes all documented political donors. Senate vote narrowly passed with Family First support.","confidence_notes":"Broadcasting Services Amendment Act 2006. Senate Hansard. Media ownership tracking."},"what_changed":"Before Vocational Education Quality Framework (2006), VET systems had inconsistent quality across jurisdictions. The framework aimed to establish national standards and quality assurance. After implementation, compliance improved but funding gaps persisted. VET trainers earned significantly less than university academics, and student completion rates remained below target, suggesting structural underfunding rather than quality standards drove outcomes."},
  {"ext":"au-pol-232","date":"2006-01-01","title":"Olympic Dam Expansion Proposal (BHP)","category":"mining","impact_score":7,"confidence_score":0.78,"primary_beneficiaries":["BHP Billiton","Uranium export industry","SA state revenue"],"disadvantaged_groups":["Great Artesian Basin water users","Local Indigenous communities","Environmental protection"],"revenue_impact":"Proposed $20B expansion (later shelved); would have consumed 150ML/day of GAB water","corporate_advantage":true,"conflict_of_interest_flags":[],"linked_donations":[],"comparison_country":"Canada","comparison_approach":"Canada requires comprehensive environmental and Indigenous impact assessments for uranium mines","comparison_outcome":"Canada maintained stronger environmental oversight; Australia fast-tracked Olympic Dam through special indenture act","analysis_json":{"corruption_signal_strength":"moderate","corruption_signal_reasoning":"BHP given special exemptions through SA Indenture Act. Proposed 150ML/day water extraction from Great Artesian Basin. Environmental assessment streamlined. BHP major political donor.","confidence_notes":"SA Olympic Dam Indenture. BHP expansion EIS. AEC donation records."},"what_changed":"Before the 2007 Rudd Election (context date 2006 reference), Work Choices had made labour market reforms heavily favoring employers. The Howard Government had stripped protections and enabled individual agreements. Before the November 2007 election, polls showed strong public rejection of Work Choices. After Rudd's election victory and Labor's first-term labor reforms, Work Choices was dismantled and bargaining protections were substantially restored through the Fair Work Act (2009)."},
  {"ext":"au-pol-233","date":"2006-01-01","title":"PBS Brand Premium System Introduced","category":"healthcare","impact_score":5,"confidence_score":0.75,"primary_beneficiaries":["Generic medicine producers","Government budget (savings)","Consumers (lower prices)"],"disadvantaged_groups":["Brand-name pharmaceutical companies","Patients preferring brand medicines (co-payment premium)"],"revenue_impact":"$1B+ savings over 5 years through generic substitution","corporate_advantage":false,"conflict_of_interest_flags":[],"linked_donations":[],"comparison_country":"New Zealand","comparison_approach":"NZ PHARMAC aggressive generic substitution and tender process","comparison_outcome":"NZ achieved even lower drug prices; Australia brand premium preserved some brand preference","analysis_json":{"corruption_signal_strength":"weak","corruption_signal_reasoning":"Reform shifted some costs but also drove generic uptake. Pharmaceutical lobby resisted stronger measures.","confidence_notes":"PBS reform documents. Department of Health price data."},"what_changed":"Before Corporate Tax Rate Reform (2006), Australia maintained a 30% corporate tax rate. Successive proposals to adjust rates were debated but not implemented during this period. After various reform proposals from 2006-2010, the rate remained at 30% until later reductions to 25% (2015 proposal, not implemented) and eventual 25% rate for smaller businesses (2021). The 2006 period shows policy deliberation without implementation."},
  {"ext":"au-pol-234","date":"2006-07-01","title":"Simpler Super Reforms Legislated (Tax Free at 60)","category":"superannuation","impact_score":8,"confidence_score":0.88,"primary_beneficiaries":["High-wealth super holders","Self-managed super funds","Financial advisors"],"disadvantaged_groups":["Low-income workers","Government revenue","Retirement income equity"],"revenue_impact":"Tax-free super withdrawals cost $8.3B annually in foregone revenue (growing)","corporate_advantage":true,"conflict_of_interest_flags":[{"member":"Peter Costello (Treasurer)","interest":"Implemented Simpler Super reforms","relevance":"Reforms disproportionately benefited wealthy; top 1% of super balances received 20% of tax concessions"}],"linked_donations":[],"comparison_country":"United Kingdom","comparison_approach":"UK taxes pension withdrawals as income; 25% tax-free lump sum max","comparison_outcome":"Australia uniquely generous tax treatment for wealthy retirees; no other OECD country offers tax-free withdrawals","analysis_json":{"corruption_signal_strength":"moderate","corruption_signal_reasoning":"Tax-free super for over-60s uniquely generous globally. Top 10% of super balances receive majority of benefit. Financial services industry lobbied strongly for reforms. Costello acknowledged regressive nature.","confidence_notes":"Treasury Tax Expenditure Statements. Henry Tax Review 2010. Grattan Institute analysis."},"what_changed":"Before Water Market Reforms (2006), the National Water Initiative framework was establishing water entitlements. Major reforms ensured permanent entitlements were tradeable and available through open market processes. After reforms, water markets grew to $3B+ annually, but large agricultural corporations (Cubbie Station, etc.) held majority of entitlements. Small farmers and Indigenous communities remained excluded from substantial water access, demonstrating how market-based allocation embedded historical inequities."},
  {"ext":"au-pol-235","date":"2006-07-01","title":"Transition to Retirement Rules Implemented","category":"superannuation","impact_score":5,"confidence_score":0.78,"primary_beneficiaries":["High-income earners","Financial advisors","Super fund managers"],"disadvantaged_groups":["Government revenue","Retirement income equity"],"revenue_impact":"$1B+ annually in tax revenue loss until 2017 reforms","corporate_advantage":true,"conflict_of_interest_flags":[],"linked_donations":[],"comparison_country":"United Kingdom","comparison_approach":"UK pension access rules simpler without equivalent transition regime","comparison_outcome":"Australia TTR used primarily as tax minimisation vehicle; UK simpler approach","analysis_json":{"corruption_signal_strength":"weak","corruption_signal_reasoning":"TTR became tax minimisation tool for high earners. Later partially addressed by 2017 reforms.","confidence_notes":"APRA TTR data. Productivity Commission super inquiry."},"what_changed":"Before Regional Telecommunications Infrastructure Grants (2006), rural Australia had limited broadband access. The government provided infrastructure grants to telecommunications companies to extend coverage to regional areas. After grants distributed, coverage expanded but at speeds below metropolitan standards. The program benefited telecommunications companies while rural Australians remained with inferior service, demonstrating subsidy-dependent service models."},
  {"ext":"au-pol-236","date":"2006-07-01","title":"Welfare to Work - Parenting Payment Tightened","category":"subsidy","impact_score":6,"confidence_score":0.78,"primary_beneficiaries":["Government budget savings","Employment services providers"],"disadvantaged_groups":["Single parents","Women with school-age children","Low-income families"],"revenue_impact":"$800M savings over 4 years; 100,000+ single parents moved to Newstart","corporate_advantage":true,"conflict_of_interest_flags":[],"linked_donations":[],"comparison_country":"Scandinavia","comparison_approach":"Scandinavian countries maintained generous parental support with subsidised childcare","comparison_outcome":"Scandinavian approach supported parents into work; Australia cut payments forcing poverty","analysis_json":{"corruption_signal_strength":"weak","corruption_signal_reasoning":"Cost-shifting from government to vulnerable single parents. Employment services providers benefited from increased clients.","confidence_notes":"FaCS evaluation. Senate Community Affairs inquiry. ACOSS poverty data."},"what_changed":"Before Smallholder Succession Planning (2006), agricultural properties faced intergenerational transfer challenges. Tax policy allowing farms to pass through generations at concessional rates enabled succession but benefited primarily wealthy farming families. After such provisions, agricultural land concentration continued while small farms exited production. Concessions were valued but ineffective at preserving small-scale farming as a proportion of agricultural output."},
  {"ext":"au-pol-237","date":"2007-08-27","title":"Alcopops Tax Increase (70%)","category":"tax","impact_score":5,"confidence_score":0.78,"primary_beneficiaries":["Public health outcomes","Spirits industry (substitution)","Government revenue"],"disadvantaged_groups":["Young drinkers","RTD manufacturers (Diageo, etc)"],"revenue_impact":"$3.1B additional revenue 2008-2012","corporate_advantage":false,"conflict_of_interest_flags":[],"linked_donations":[],"comparison_country":"United Kingdom","comparison_approach":"UK minimum unit pricing in Scotland (2018)","comparison_outcome":"UK minimum pricing more effective at reducing harm; Australia alcopops tax shifted consumption to other alcohol","analysis_json":{"corruption_signal_strength":"none","corruption_signal_reasoning":"Public health taxation with legitimate objectives.","confidence_notes":"ATO excise data. AIHW alcohol consumption data."},"what_changed":"Before the 2006 ABS Census, Australia conducted its decennial census every ten years (previous 1996). The 2006 Census provided updated demographics enabling policy targeting. After data collection, the census showed increasing concentration of immigration in specific urban areas, with regional Australia's population share declining. Policy responses remained limited, with regional development funding remaining inadequate relative to demographic decline."},
  {"ext":"au-pol-238","date":"2007-10-18","title":"Cross-Media Ownership Reforms Enacted","category":"media","impact_score":7,"confidence_score":0.82,"primary_beneficiaries":["News Corp","Seven West Media","Nine Entertainment"],"disadvantaged_groups":["Media diversity","Local journalism","Community media"],"revenue_impact":"Enabled Nine-Fairfax $4B merger; further consolidation ongoing","corporate_advantage":true,"conflict_of_interest_flags":[],"linked_donations":[],"comparison_country":"Germany","comparison_approach":"Germany maintained cross-media limits through KEK regulator","comparison_outcome":"Germany preserved plurality; Australia accelerated consolidation","analysis_json":{"corruption_signal_strength":"strong","corruption_signal_reasoning":"Media proprietors documented as major political donors. Reforms directly benefited donor class. Media consolidation reduced scrutiny of government.","confidence_notes":"BSA amendments. ACMA ownership data. AEC media company donation records."},"what_changed":"Before Indigenous Affairs Policy (2006), the Howard Government had pursued 'practical reconciliation' without addressing structural disadvantage. Policies aimed at cultural assimilation continued while Indigenous poverty and health gaps persisted. After various modest programs, Indigenous life expectancy remained 10+ years below non-Indigenous Australians. Structural inequality in health, income, and opportunity remained unchanged despite policy effort."},
  {"ext":"au-pol-239","date":"2007-09-10","title":"Gorgon LNG Project Federal Approval","category":"oil_gas","impact_score":8,"confidence_score":0.85,"primary_beneficiaries":["Chevron","ExxonMobil","Shell","LNG export industry"],"disadvantaged_groups":["Barrow Island environment","Climate policy","PRRT revenue (concessions)"],"revenue_impact":"$54B project (blew out to $75B); Chevron paid $0 in PRRT on Gorgon until 2023","corporate_advantage":true,"conflict_of_interest_flags":[{"member":"Environment Minister","interest":"Approved project on Class A Nature Reserve (Barrow Island)","relevance":"World-first approval of LNG plant on nature reserve; environmental conditions weakened from draft"}],"linked_donations":[],"comparison_country":"Norway","comparison_approach":"Norway applies 78% tax rate on petroleum profits; no nature reserve exemptions","comparison_outcome":"Norway captured $500B+ from equivalent projects; Australia captured minimal PRRT from Gorgon for 15+ years","analysis_json":{"corruption_signal_strength":"strong","corruption_signal_reasoning":"Chevron paid $0 PRRT on $54-75B project for 15+ years. Approved on Class A Nature Reserve. Environmental conditions weakened. Chevron documented political donor to both parties.","confidence_notes":"Chevron PRRT data from ATO transparency reports. Gorgon EIS. AEC donation records."},"what_changed":"Before Defence White Paper 2006, Australia reviewed its defence posture and capabilities. The White Paper endorsed continued reliance on US alliance, F-35 procurement, and naval expansion. After this policy framework, Australia committed to massive defence spending (JSF, ships, etc.) with limited strategic assessment of whether threats justified the expenditure. The policy entrenched high defence spending and US procurement dependence for the subsequent decade."},
  {"ext":"au-pol-240","date":"2007-06-21","title":"NT National Emergency Response (Intervention)","category":"subsidy","impact_score":8,"confidence_score":0.88,"primary_beneficiaries":["Government Departments","Contractors deployed to NT","Military logistics"],"disadvantaged_groups":["Indigenous communities","Aboriginal land rights","Self-determination"],"revenue_impact":"$1.5B over 5 years; suspended Racial Discrimination Act","corporate_advantage":true,"conflict_of_interest_flags":[],"linked_donations":[],"comparison_country":"Canada","comparison_approach":"Canada addressed First Nations issues through negotiation and increased funding","comparison_outcome":"Canada imperfect but maintained self-determination principles; Australia suspended rights and imposed control","analysis_json":{"corruption_signal_strength":"moderate","corruption_signal_reasoning":"Suspended Racial Discrimination Act to implement. Compulsory income management and land acquisition. Contractor deployment costs significant. Later reviews found limited evidence of effectiveness.","confidence_notes":"NT Emergency Response legislation. Closing the Gap reports. NTER Review Board."},"what_changed":"Before Disability Support Pension (DSP) Tightening (2006), eligibility for DSP was based on permanent incapacity assessment. Successive governments tightened assessment criteria aiming to move people from DSP to other support or employment. After tightening, DSP rolls declined but many former recipients fell into unemployment or inadequate income support. The policy reduced headline DSP numbers without improving underlying employment or income outcomes for people with disabilities."},
  {"ext":"au-pol-241","date":"2007-01-01","title":"National Early Childhood Development Strategy (COAG)","category":"education","impact_score":6,"confidence_score":0.75,"primary_beneficiaries":["Children","Early childhood educators","Private childcare operators"],"disadvantaged_groups":["Low-income families (access gaps)","Rural communities"],"revenue_impact":"$4B+ annually in early childhood education and care funding","corporate_advantage":false,"conflict_of_interest_flags":[],"linked_donations":[],"comparison_country":"Finland","comparison_approach":"Finland universal early childhood education with high-quality public provision","comparison_outcome":"Finland top-ranked early education; Australia quality variable across for-profit and not-for-profit sectors","analysis_json":{"corruption_signal_strength":"none","corruption_signal_reasoning":"Legitimate early childhood development initiative.","confidence_notes":"COAG NQF documents. ACECQA quality reports."},"what_changed":"Before Strengthening Community Outcomes (2006), Australian community services operated with fragmented funding and accountability. The government aimed to strengthen outcomes reporting and efficiency. After this initiative, performance measurement improved but actual service outcomes for vulnerable populations remained constrained by absolute funding levels. Measurement improvements did not translate into service quality improvements when funding remained inadequate."},
  {"ext":"au-pol-242","date":"2007-06-21","title":"Northern Territory Emergency Response Implementation","category":"subsidy","impact_score":8,"confidence_score":0.88,"primary_beneficiaries":["Government agencies","Contractors","Military logistics providers"],"disadvantaged_groups":["Indigenous communities","Aboriginal self-determination","Land rights"],"revenue_impact":"$1.5B over 5 years","corporate_advantage":true,"conflict_of_interest_flags":[],"linked_donations":[],"comparison_country":"New Zealand","comparison_approach":"NZ Treaty of Waitangi framework for addressing Indigenous issues through negotiation","comparison_outcome":"NZ maintained treaty-based engagement; Australia imposed emergency measures suspending rights","analysis_json":{"corruption_signal_strength":"moderate","corruption_signal_reasoning":"Suspended Racial Discrimination Act. Compulsory income management. Significant contractor deployment. NTER Review found limited evidence of stated objectives being met.","confidence_notes":"NTER Act 2007. Review Board report. Closing the Gap data."},"what_changed":"Before the Northern Territory Emergency Response (NTER, 2007), Indigenous communities in the Northern Territory operated under standard legal frameworks. Following a report of child sexual abuse, the federal government imposed emergency measures including: suspending Racial Discrimination Act provisions, implementing compulsory income management, and deploying military/government staff. After NTER implementation over five years, the initiative was reviewed and found to have achieved limited evidence of stated objectives while suspending Indigenous rights and community self-determination. New Zealand by contrast maintained treaty-based negotiation frameworks."},
  {"ext":"au-pol-243","date":"2007-01-01","title":"PBS Price Disclosure Regime Introduced","category":"healthcare","impact_score":6,"confidence_score":0.78,"primary_beneficiaries":["Government budget","Consumers","Generic medicine access"],"disadvantaged_groups":["Pharmaceutical companies (reduced margins)","Local pharma manufacturing"],"revenue_impact":"$4B+ savings over 10 years through price disclosure","corporate_advantage":false,"conflict_of_interest_flags":[],"linked_donations":[],"comparison_country":"New Zealand","comparison_approach":"NZ PHARMAC tender process achieves even lower drug prices","comparison_outcome":"NZ PHARMAC more aggressive on pricing; Australia price disclosure moderate approach","analysis_json":{"corruption_signal_strength":"none","corruption_signal_reasoning":"Legitimate pharmaceutical pricing reform. Pharmaceutical industry resisted but reform proceeded.","confidence_notes":"PBS reform documentation. Department of Health price data."},"what_changed":"Before PBS Price Disclosure Regime (2007), pharmaceutical companies negotiated prices with government in confidentiality. The regime required prices to be disclosed and benchmarked against international comparisons. After implementation, the policy provided transparency enabling government to identify overpricing, generating approximately $4B+ in savings over ten years through better negotiating position. The policy demonstrated that transparency in pricing enables public systems to negotiate better terms."},
  {"ext":"au-pol-244","date":"2007-12-03","title":"Ratification of Kyoto Protocol","category":"oil_gas","impact_score":7,"confidence_score":0.88,"primary_beneficiaries":["Renewable energy sector","Climate policy advocates","International reputation"],"disadvantaged_groups":["Coal industry","Fossil fuel sector"],"revenue_impact":"Symbolic commitment; Australia target 108% of 1990 levels (easy to meet)","corporate_advantage":false,"conflict_of_interest_flags":[],"linked_donations":[],"comparison_country":"European Union","comparison_approach":"EU committed to 8% below 1990 levels with binding targets per member state","comparison_outcome":"EU achieved meaningful reduction targets; Australia committed to 8% increase above 1990 (easily met through accounting)","analysis_json":{"corruption_signal_strength":"weak","corruption_signal_reasoning":"First act of Rudd government. Australia Kyoto target (108% of 1990) was among weakest; easily met without real emission reductions.","confidence_notes":"UNFCCC Kyoto Protocol. DCCEE national inventory reports."},"what_changed":"Before Kyoto Protocol Ratification (2007), Australia was the only developed nation to refuse signing the protocol. The Howard Government had opposed Kyoto, claiming economic harm. After the Rudd Government's election, Australia immediately ratified Kyoto in December 2007. However, Australia's target was set at 108% of 1990 emission levels—meaning Australia could increase emissions by 8% and still meet target—making Australia's commitment the weakest among developed nations and easily achievable without real emissions reductions."},
  {"ext":"au-pol-245","date":"2007-11-24","title":"Rudd Government Election - Climate/Mining/NBN","category":"tax","impact_score":8,"confidence_score":0.88,"primary_beneficiaries":["Climate policy","Education sector (Education Revolution)","NBN contractors"],"disadvantaged_groups":["Mining sector (proposed RSPT)","WorkChoices beneficiaries"],"revenue_impact":"Mandated $43B NBN, $16.2B Education Revolution, ETS development","corporate_advantage":false,"conflict_of_interest_flags":[],"linked_donations":[],"comparison_country":"New Zealand","comparison_approach":"NZ Labour government 1999-2008 implemented similar reform agenda","comparison_outcome":"Both implemented significant reform agendas in first terms","analysis_json":{"corruption_signal_strength":"none","corruption_signal_reasoning":"Democratic election with transparent mandate. Reform agenda clearly communicated to voters.","confidence_notes":"AEC election results. Rudd government policy announcements."},"what_changed":"Before the Rudd Government Election (2007), Australia had been governed by the conservative Howard Government (1996-2007) with emphasis on market-based policies and strong US alliance. The Rudd Labor Government elected November 2007 campaigned on climate action, education revolution, and NBN infrastructure. After Rudd's election, the government announced the National Broadband Network ($43B), Education Revolution ($16.2B), and initiated climate change policy. These commitments represented significant ideological shift toward public investment after 11 years of market emphasis."},
  {"ext":"au-pol-246","date":"2008-07-16","title":"CPRS Carbon Scheme Announced","category":"oil_gas","impact_score":8,"confidence_score":0.85,"primary_beneficiaries":["Renewable energy sector","Carbon market traders","Energy efficiency industry"],"disadvantaged_groups":["Coal industry","Heavy industry","Electricity consumers (short-term)"],"revenue_impact":"Proposed $11.5B over first 5 years; ultimately defeated in Senate","corporate_advantage":false,"conflict_of_interest_flags":[],"linked_donations":[],"comparison_country":"European Union","comparison_approach":"EU ETS operating since 2005 with progressively tighter caps","comparison_outcome":"EU achieved functioning carbon market; Australia CPRS defeated twice in Senate; carbon pricing not achieved until 2012","analysis_json":{"corruption_signal_strength":"moderate","corruption_signal_reasoning":"Mining and fossil fuel industry lobbied heavily against CPRS. $22M advertising campaign by mining sector. Coalition shifted from supporting to opposing after leadership change. Industry donations to Coalition during this period documented.","confidence_notes":"Senate Hansard. Mining industry advertising spend records. AEC donation data."},"what_changed":"Before the Carbon Pollution Reduction Scheme (CPRS, 2008), Australia had debated emissions trading mechanisms for years. Rudd Government announced the CPRS in July 2008 as the centrepiece of climate policy, proposing $11.5B over five years. After announcement, the mining sector (particularly coal) launched a $22 million advertising campaign opposing the scheme. Opposition Coalition members who had previously supported emissions trading switched to opposition after leadership change. The CPRS failed to pass Senate twice and was abandoned, with Australia not achieving carbon pricing until 2012.","flag_explanations":[{"label":"Mining sector $22M advertising campaign against CPRS","detail":"Coal and other mining companies deployed $22 million advertising campaign in 2009 opposing the CPRS. Does not prove corruption but shows organized industry opposition captured political outcomes."},{"label":"Coalition leadership change shifted party position on carbon pricing","detail":"Coalition members who had previously supported emissions trading switched to opposition after leadership change in 2009. Does not prove corruption but shows policy positions shifted aligned with mining sector opposition."},{"label":"CPRS failed Senate votes despite government super-majority in House","detail":"Government legislation failed to pass Senate (not controlled by government) despite strong initial support. Mining industry opposition and Coalition party switch to opposition defeated the scheme. Does not prove corruption but shows organized industry opposition defeated policy."}]},
  {"ext":"au-pol-247","date":"2008-02-18","title":"FIRB Blocked Chinalco-Rio Tinto Deal","category":"financial_regulation","impact_score":7,"confidence_score":0.82,"primary_beneficiaries":["Rio Tinto shareholders (ultimately higher prices)","BHP (maintained competition)","National security"],"disadvantaged_groups":["Chinalco (Chinese state investor)","Bilateral trade relationship"],"revenue_impact":"Blocked $19.5B Chinalco stake; Rio Tinto share price recovered","corporate_advantage":true,"conflict_of_interest_flags":[],"linked_donations":[],"comparison_country":"Canada","comparison_approach":"Canada Investment Canada Act blocked similar Chinese SOE acquisitions (Nexen exception)","comparison_outcome":"Both nations applied national interest tests to Chinese SOE investments; both maintained screening frameworks","analysis_json":{"corruption_signal_strength":"weak","corruption_signal_reasoning":"National security screening with legitimate rationale. No corruption signal identified.","confidence_notes":"FIRB annual reports. Treasury decisions. Media reporting."},"what_changed":"Before FIRB Block of Chinalco-Rio Tinto (2008), Chinese state-owned enterprises were increasingly investing in Australian resources. Chinalco proposed a $19.5 billion equity stake in Rio Tinto during the global financial crisis. The government-appointed Foreign Investment Review Board blocked the deal citing national interest concerns. After the decision, Rio Tinto's share price recovered and shareholders benefited, while Australia maintained control of one of the world's largest mining companies. Canada applied similar national interest tests to similar Chinese SOE acquisition proposals."},
  {"ext":"au-pol-248","date":"2008-10-14","title":"GFC First Stimulus ($10.4B)","category":"subsidy","impact_score":8,"confidence_score":0.88,"primary_beneficiaries":["Low-income households","Pensioners","First home buyers","Retailers"],"disadvantaged_groups":["Higher-income earners (no payments)","Government debt position"],"revenue_impact":"$10.4B cash payments; $900 per individual; avoided recession","corporate_advantage":false,"conflict_of_interest_flags":[],"linked_donations":[],"comparison_country":"United States","comparison_approach":"US TARP ($700B) focused on bank bailouts rather than household stimulus","comparison_outcome":"Australia avoided recession (unique among developed nations); US recession lasted 18 months despite larger intervention","analysis_json":{"corruption_signal_strength":"none","corruption_signal_reasoning":"Emergency fiscal stimulus with transparent public interest rationale. Australia only major economy to avoid recession.","confidence_notes":"Treasury GFC response documents. RBA analysis. IMF commendation of Australian response."},"what_changed":"Before GFC First Stimulus (October 2008), Australia was experiencing the global financial crisis impact with credit seizure and economic contraction. The government deployed a $10.4 billion cash stimulus, paying $900 per individual to households. After implementation, Australia uniquely avoided recession among developed nations, maintained employment near pre-crisis levels, and continued economic growth. The US by contrast deployed $700 billion TARP focused on bank bailouts rather than household stimulus and suffered an 18-month recession."},
  {"ext":"au-pol-249","date":"2008-12-12","title":"GFC Investment Tax Credit (50% Bonus Depreciation)","category":"tax","impact_score":6,"confidence_score":0.78,"primary_beneficiaries":["Business sector","Capital equipment suppliers","Mining companies"],"disadvantaged_groups":["Government revenue","Non-business taxpayers"],"revenue_impact":"$2.7B in accelerated depreciation benefits","corporate_advantage":true,"conflict_of_interest_flags":[],"linked_donations":[],"comparison_country":"United States","comparison_approach":"US bonus depreciation 50-100% during GFC and extended post-GFC","comparison_outcome":"Both used accelerated depreciation as stimulus; US maintained longer than Australia","analysis_json":{"corruption_signal_strength":"weak","corruption_signal_reasoning":"Standard GFC fiscal stimulus measure benefiting business investment.","confidence_notes":"Treasury GFC response. ATO depreciation data."},"what_changed":"Before GFC Investment Tax Credit (2008), Australian businesses faced contraction and reduced capital investment. The government introduced 50% bonus depreciation allowing accelerated deductions for capital equipment. After introduction, the policy provided $2.7B in tax benefits to encourage business investment during the crisis. The US deployed similar bonus depreciation provisions (extended both percentage and duration relative to Australia), maintaining stimulus longer into the recovery."},
  {"ext":"au-pol-250","date":"2008-07-01","title":"Luxury Car Tax Increase (33%)","category":"tax","impact_score":4,"confidence_score":0.8,"primary_beneficiaries":["Government revenue","Australian car manufacturers (relative advantage)"],"disadvantaged_groups":["Luxury car buyers","European car importers"],"revenue_impact":"$500M annually in LCT revenue","corporate_advantage":false,"conflict_of_interest_flags":[],"linked_donations":[],"comparison_country":"Singapore","comparison_approach":"Singapore uses COE system and ARF for vehicle taxation","comparison_outcome":"Singapore more effective at managing car ownership; Australia LCT minor revenue measure","analysis_json":{"corruption_signal_strength":"none","corruption_signal_reasoning":"Revenue measure with transparent mechanism. No corruption signal.","confidence_notes":"ATO LCT data. Treasury revenue estimates."},"what_changed":"Before Luxury Car Tax Increase (2008), Australia maintained a 10% luxury car tax on vehicles over a threshold. The government increased the rate to 33% to raise revenue and encourage purchase of local vehicles. After the increase, LCT revenue reached approximately $500M annually but had minimal impact on luxury car purchases (demand is price-inelastic for this segment) or on domestic car industry competitiveness. The policy was primarily a revenue measure without apparent policy objectives."}
];

